#include <iostream>
#include <vector>
class Solution {
public:
	int search(std::vector<int>& nums, int target) {
		if (target < nums[0] || target > nums[nums.size() - 1]) return -1;
		int start = 0, end = nums.size() - 1;
		while (start <= end) {
			int mid = (start + end) / 2;
			if (nums[mid] == target) return mid;
			if (nums[mid] < target) start = mid + 1;
			else end = mid - 1;
		}
		return -1;
	}
};
int main() {
	std::vector<int> nums = {2, 5, 8, 12, 16, 23, 38, 56, 72, 91};
	Solution solution;
	int target = 23;
	std::cout << solution.search(nums, target) << std::endl;
	return 0;
}
